#include<bits/stdc++.h>
using namespace std;
bool v[2001][2001];
int n;
void dfs(int x1,int x2,int y1,int y2){
    if(x1==x2&&x1==y2&&y2==y1) return;
    if(x1>=x2||y1>=y2) return;
    for(int i=y1;i<=y1+(y2-y1)/2;i++){
        for(int j=x1;j<=x1+(x2-x1)/2;j++){
            v[i][j]=1;
        }
    }
    dfs(x1+(x2-x1)/2+1,x2,y1,y1+(y2-y1)/2);
    dfs(x1,x1+(x2-x1)/2,y1+(y2-y1)/2+1,y2);
    dfs(x1+(x2-x1)/2+1,x2,y1+(y2-y1)/2+1,y2);
}
int main(){
    cin>>n;
    dfs(1,pow(2,n),1,pow(2,n));
    for(int i=1;i<=pow(2,n);i++){
        for(int j=1;j<=pow(2,n);j++){
            cout<<!v[i][j]<<' ';
        }
        cout<<"\n";
    }
    return 0;
}
